// types.d.ts
/**
 * TypeScript type definitions for the WeatherCard component and all sub-components
 */

/**
 * Represents a single day's forecast data
 */
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

/**
 * Props for the main WeatherCard component
 */
export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

/**
 * Props for displaying current temperature and weather condition
 */
export interface CurrentWeatherProps {
  temperature: number;
  condition: string;
  unit?: string;
}

/**
 * Props for displaying weather metrics (humidity, wind speed)
 */
export interface WeatherMetricsProps {
  humidity: number;
  windSpeed: number;
}

/**
 * Props for a single forecast day card
 */
export interface ForecastCardProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unit?: string;
}

/**
 * Props for the forecast strip container
 */
export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit?: string;
}

/**
 * Props for the weather card header
 */
export interface WeatherHeaderProps {
  city: string;
}

/**
 * Return type for weather data processing hooks
 */
export interface HookReturn {
  formattedCondition: string;
  conditionIcon: string;
  displayTemp: number | string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

/**
 * Weather condition to emoji/icon mapping
 * Maps weather condition strings to appropriate visual representations
 * Used throughout the component for condition display
 */
export const WEATHER_ICONS = {
  sunny: "☀️",
  cloudy: "☁️",
  "partly cloudy": "⛅",
  partlycloudy: "⛅",
  rainy: "🌧️",
  snowy: "❄️",
  windy: "💨",
  thunderstorm: "⛈️",
  foggy: "🌫️",
  clear: "🌙",
} as const;

/**
 * Temperature unit display symbols
 * Maps unit abbreviations to their display symbols
 * Used in CurrentWeather and ForecastCard components
 */
export const TEMP_UNITS = {
  C: "°C",
  F: "°F",
  K: "K",
} as const;

/**
 * Default configuration values
 * Fallback values for optional props and component behavior
 */
export const DEFAULTS = {
  DEFAULT_UNIT: "F",
} as const;

/**
 * Forecast display configuration
 * Controls how many forecast days are shown and display settings
 */
export const FORECAST_CONFIG = {
  DAYS_TO_DISPLAY: 5,
} as const;


// --- hooks.ts ---
// hooks.ts
import { HookReturn } from './types';

/**
 * Condition to icon mapping
 * Maps weather conditions to their display names and emoji icons
 */
const CONDITION_ICON_MAP: Record<string, { formatted: string; icon: string }> = {
  sunny: { formatted: 'Sunny', icon: '☀️' },
  clear: { formatted: 'Clear', icon: '☀️' },
  cloudy: { formatted: 'Cloudy', icon: '☁️' },
  'partly cloudy': { formatted: 'Partly Cloudy', icon: '⛅' },
  rainy: { formatted: 'Rainy', icon: '🌧️' },
  rain: { formatted: 'Rainy', icon: '🌧️' },
  thunderstorm: { formatted: 'Thunderstorm', icon: '⛈️' },
  snowy: { formatted: 'Snowy', icon: '❄️' },
  snow: { formatted: 'Snowy', icon: '❄️' },
  foggy: { formatted: 'Foggy', icon: '🌫️' },
  fog: { formatted: 'Foggy', icon: '🌫️' },
  windy: { formatted: 'Windy', icon: '💨' },
  wind: { formatted: 'Windy', icon: '💨' },
};

/**
 * Default icon for unknown conditions
 */
const DEFAULT_ICON = '🌤️';

/**
 * useWeatherCard Hook
 * 
 * Processes raw weather data and returns formatted condition, icon, and display temperature.
 * 
 * @param condition - The weather condition string (e.g., "Partly Cloudy")
 * @param temperature - The temperature value
 * @param unit - Optional unit of measurement (defaults to 'C' for Celsius)
 * @returns HookReturn object with formatted condition, icon, and display temperature
 */
export const useWeatherCard = (
  condition: string,
  temperature: number,
  unit: string = 'C'
): HookReturn => {
  // Normalize condition: trim whitespace and convert to lowercase for matching
  const normalizedCondition = String(condition || '')
    .trim()
    .toLowerCase();

  // Get condition mapping or use original condition with default icon
  const conditionData = CONDITION_ICON_MAP[normalizedCondition];

  let formattedCondition: string;
  let conditionIcon: string;

  if (conditionData) {
    formattedCondition = conditionData.formatted;
    conditionIcon = conditionData.icon;
  } else {
    // Fallback: use original condition string (with first letter capitalized) and default icon
    formattedCondition = normalizedCondition
      ? normalizedCondition.charAt(0).toUpperCase() + normalizedCondition.slice(1)
      : 'Unknown';
    conditionIcon = DEFAULT_ICON;
  }

  // Format display temperature
  let displayTemp: number | string;
  if (temperature !== null && temperature !== undefined && !isNaN(temperature)) {
    const roundedTemp = Math.round(temperature);
    displayTemp = `${roundedTemp}°${unit}`;
  } else {
    displayTemp = 'N/A';
  }

  return {
    formattedCondition,
    conditionIcon,
    displayTemp,
  };
};


