// components/CurrentWeather.tsx
import { Card, Stack, Heading, Text } from '@ggui-ai/design/primitives';
import { CurrentWeatherProps } from '../types';

export const CurrentWeather: React.FC<CurrentWeatherProps> = ({
  temperature,
  condition,
  unit = 'C',
}) => {
  /**
   * Maps weather condition string to appropriate emoji
   */
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    const emojiMap: Record<string, string> = {
      sunny: '☀️',
      cloudy: '☁️',
      rainy: '🌧️',
      snowy: '❄️',
      stormy: '⛈️',
    };
    return emojiMap[condLower] || '🌤️';
  };

  const weatherEmoji = getWeatherEmoji(condition);
  const displayTemp = `${temperature}°${unit}`;
  const displayCondition = condition.charAt(0).toUpperCase() + condition.slice(1);

  return (
    <Card padding={24} shadow="sm">
      <Stack direction="vertical" align="center" gap={16}>
        <div style={{ fontSize: '72px', lineHeight: '1' }}>
          {weatherEmoji}
        </div>
        <Heading level={2}>{displayTemp}</Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {displayCondition}
        </Text>
      </Stack>
    </Card>
  );
};

