import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { WeatherMetricsProps } from '../types';

/**
 * WeatherMetrics Component
 * Displays humidity and wind speed in a horizontal metrics layout
 * 
 * @param humidity - Humidity percentage (0-100)
 * @param windSpeed - Wind speed value in km/h
 * @returns Rendered weather metrics display
 */
export const WeatherMetrics: React.FC<WeatherMetricsProps> = ({
  humidity,
  windSpeed,
}) => {
  return (
    <Stack
      direction="horizontal"
      gap={parseInt('var(--ggui-spacing-4, 16px)', 10) || 16}
      align="center"
      justify="between"
      style={{
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      {/* Humidity Metric */}
      <Stack gap={parseInt('var(--ggui-spacing-2, 8px)', 10) || 8} align="start">
        <Text
          variant="label"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          Humidity
        </Text>
        <Text
          variant="bodyLarge"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="semibold"
        >
          {humidity}%
        </Text>
      </Stack>

      {/* Wind Speed Metric */}
      <Stack gap={parseInt('var(--ggui-spacing-2, 8px)', 10) || 8} align="start">
        <Text
          variant="label"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          Wind Speed
        </Text>
        <Text
          variant="bodyLarge"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="semibold"
        >
          {windSpeed} km/h
        </Text>
      </Stack>
    </Stack>
  );
};


