// components/ForecastCard.tsx
import React from 'react';
import { Card, Stack, Text, Box } from '@ggui-ai/design/primitives';
import type { ForecastCardProps } from '../types';

/**
 * ForecastCard Component
 * 
 * Displays a single day's forecast in a compact card format.
 * Shows the day name, weather icon, and high/low temperatures.
 * 
 * @component
 * @example
 * <ForecastCard day="Mon" icon="☀️" high={28} low={18} unit="°C" />
 */
export const ForecastCard: React.FC<ForecastCardProps> = ({
  day,
  icon,
  high,
  low,
  unit = '°C'
}) => {
  return (
    <Card
      padding={`${parseInt('16')} ${parseInt('8')}`}
      shadow="sm"
      border={true}
      radius="md"
      style={{
        textAlign: 'center',
        minWidth: '80px',
        flexShrink: 0
      }}
    >
      <Stack direction="vertical" align="center" gap={8}>
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {day.toUpperCase()}
        </Text>
        <div style={{ fontSize: '32px', margin: 'var(--ggui-spacing-2) 0' }}>
          {icon}
        </div>
        <Stack direction="horizontal" align="center" gap={8}>
          <Text weight="bold" color="var(--ggui-color-onSurface, #18181b)">{high}{unit}</Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{low}{unit}</Text>
        </Stack>
      </Stack>
    </Card>
  );
};


