// components/ForecastStrip.tsx
import React from 'react';
import { Box } from '@ggui-ai/design/primitives';
import { ForecastCard } from './ForecastCard';
import { ForecastStripProps } from './types';

export const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast, unit = '°C' }) => {
  // Handle edge case: empty forecast array
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <Box
      style={{
        display: 'flex',
        flexDirection: 'row',
        gap: 'var(--ggui-spacing-4, 16px)',
        overflowX: 'auto',
        flexWrap: 'nowrap',
        paddingTop: 'var(--ggui-spacing-4, 16px)',
        paddingBottom: 'var(--ggui-spacing-4, 16px)',
        paddingLeft: 'var(--ggui-spacing-6, 24px)',
        paddingRight: 'var(--ggui-spacing-6, 24px)',
        scrollBehavior: 'smooth',
      }}
    >
      {forecast.map((day) => (
        <div
          key={day.day}
          style={{
            flexShrink: 0,
          }}
        >
          <ForecastCard
            day={day.day}
            icon={day.icon}
            high={day.high}
            low={day.low}
            unit={unit}
          />
        </div>
      ))}
    </Box>
  );
};


