// ui.tsx
import React from 'react';
import {
  Card,
  Stack,
  Divider,
  Text,
  Heading
} from '@ggui-ai/design/primitives';

import { WeatherHeader } from './components/WeatherHeader';
import { CurrentWeather } from './components/CurrentWeather';
import { WeatherMetrics } from './components/WeatherMetrics';
import { ForecastStrip } from './components/ForecastStrip';
import type { Props } from './types';

/**
 * WeatherCard Component
 *
 * Main component that composes all weather sub-components into a responsive card layout.
 * Displays current conditions, metrics (humidity/wind), and a 5-day forecast strip.
 *
 * @component
 * @example
 * <WeatherCard
 *   city="San Francisco"
 *   temperature={72}
 *   condition="Partly Cloudy"
 *   humidity={65}
 *   windSpeed={12}
 *   unit="°F"
 *   forecast={[...]}
 * />
 */
export const WeatherCard: React.FC<Props> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast
}) => {
  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack direction="vertical" gap={16}>
        {/* Header Section */}
        <WeatherHeader city={city} />

        {/* Current Weather Display */}
        <CurrentWeather temperature={temperature} condition={condition} unit={unit} />

        {/* Weather Metrics (Humidity & Wind) */}
        <WeatherMetrics humidity={humidity} windSpeed={windSpeed} />

        {/* Visual Divider */}
        <Divider margin={12} />

        {/* 5-Day Forecast Strip */}
        <ForecastStrip forecast={forecast} unit={unit} />
      </Stack>
    </Card>
  );
};

export default WeatherCard;


// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { Component } from './components/index';

